sql:
SELECT AVG(crime_rate_per_100k) AS average_crime_rate
FROM crime_statistics
WHERE state_id = (SELECT state_id FROM states WHERE state_name = 'California');

SELECT *
FROM violent_crimes
WHERE severity_level = 'High';

SELECT state_id, AVG(crime_rate_per_100k) AS average_crime_rate
FROM crime_statistics
GROUP BY state_id;

SELECT AVG(population) AS average_population
FROM states
WHERE state_id IN (
  SELECT state_id
  FROM crime_statistics
  WHERE crime_rate_per_100k < (
    SELECT AVG(crime_rate_per_100k) AS average_crime_rate
    FROM crime_statistics
  )
);

SELECT ROW_NUMBER() OVER () AS row_number, rule_name, rule_description, rule_type
FROM data_validation
WHERE rule_type = 'format';

SELECT state_id, state_name
FROM states
WHERE state_id BETWEEN 20 AND 40;

SELECT SUM(count) AS TotalIncidents2020
FROM crimes_reported
WHERE year = 2020;

external_knowledge:
- "Populous states" refers to states with populations greater than 10,000,000;
- "Recent years" means years after 2000;
- "Significant violent crime issue" refers to a violent crime rate greater than 100;
- "Crime rates" include the violent crime rate, property crime rate, and their respective rates per 100,000 inhabitants.
